-- 애터미 수당체계 학습 퀴즈 앱 — 3단계(관리자용 문제 관리 CMS) 마이그레이션
--
-- 전제: supabase-schema.sql, supabase-schema-leaderboard.sql이 이미 실행되어 있어야 합니다.
-- 사용 방법: Supabase 대시보드 > SQL Editor > New query 에 아래 전체를 붙여넣고 실행하세요.
-- (문항 156개를 시드로 함께 넣기 때문에 파일이 깁니다 — 전체를 한 번에 실행하면 됩니다.)

-- 1) 문제 데이터 테이블
--    공통 필드 + 유형별 전용 필드는 payload(jsonb)에 담아 6가지 문제 유형을
--    하나의 테이블로 유연하게 관리한다. payload 구조는 questions.js와 동일하다:
--      mc:    { choices: string[4], answerIndex: number }
--      ox:    { answer: boolean }
--      fill:  { answer: string, acceptableAnswers: string[] }
--      calc:  { answer: string, unit: string }
--      order: { items: string[] }
--      match: { pairs: { left: string, right: string }[] }
create table if not exists public.questions (
  id text primary key,
  category text not null,
  type text not null check (type in ('mc', 'ox', 'fill', 'order', 'calc', 'match')),
  difficulty text not null check (difficulty in ('초급', '중급', '고급')),
  tags jsonb not null default '[]'::jsonb,
  question text not null,
  explanation text not null,
  payload jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

-- 2) 관리자 목록 (이메일 기준). RLS에서 이 테이블을 직접 노출하지 않고
--    is_admin() 함수(SECURITY DEFINER)를 통해서만 참조한다.
create table if not exists public.admins (
  email text primary key
);

alter table public.admins enable row level security;
-- admins 테이블에는 어떤 역할에도 SELECT/INSERT 등 정책을 주지 않는다(기본 전체 차단).
-- is_admin()이 테이블 소유자 권한(SECURITY DEFINER)으로 우회해서 조회한다.

  on conflict (email) do nothing;

create or replace function public.is_admin()
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select exists (
    select 1 from public.admins where email = (auth.jwt() ->> 'email')
  );
$$;

-- 클라이언트(로그인한 사용자)가 "내가 관리자인지"만 확인할 수 있는 좁은 창구.
create or replace function public.am_i_admin()
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select public.is_admin();
$$;

revoke all on function public.is_admin() from public;
revoke all on function public.am_i_admin() from public;
grant execute on function public.am_i_admin() to authenticated;

-- 3) RLS: 문제 열람은 누구나(비로그인 포함) 가능, 등록/수정/삭제는 관리자만 가능
alter table public.questions enable row level security;

drop policy if exists "questions_select_all" on public.questions;
create policy "questions_select_all"
  on public.questions for select
  using (true);

drop policy if exists "questions_insert_admin" on public.questions;
create policy "questions_insert_admin"
  on public.questions for insert
  with check (public.is_admin());

drop policy if exists "questions_update_admin" on public.questions;
create policy "questions_update_admin"
  on public.questions for update
  using (public.is_admin())
  with check (public.is_admin());

drop policy if exists "questions_delete_admin" on public.questions;
create policy "questions_delete_admin"
  on public.questions for delete
  using (public.is_admin());

grant select on public.questions to anon, authenticated;
grant insert, update, delete on public.questions to authenticated;

-- updated_at 자동 갱신
create or replace function public.set_questions_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

drop trigger if exists trg_questions_updated_at on public.questions;
create trigger trg_questions_updated_at
  before update on public.questions
  for each row execute function public.set_questions_updated_at();

-- 4) 기존 questions.js의 156문항을 초기 데이터로 적재한다.
--    (이미 존재하는 id는 내용을 덮어써 항상 questions.js 스냅샷과 동일하게 맞춘다)
on conflict (id) do update set
  category = excluded.category,
  type = excluded.type,
  difficulty = excluded.difficulty,
  tags = excluded.tags,
  question = excluded.question,
  explanation = excluded.explanation,
  payload = excluded.payload,
  updated_at = now();

